-- Legacy Wall Charts — core competition/season shells for all named tournaments.
-- This migration is intentionally idempotent. It adds seasons and placeholder chart
-- structures so every named competition opens a real season selector and wall chart.
-- Placeholder fixtures are marked unverified with source 'data-import-pending' so they
-- cannot be mistaken for official results.

CREATE UNIQUE INDEX IF NOT EXISTS idx_rounds_season_slug_slug ON public.rounds(season_slug, slug) WHERE season_slug IS NOT NULL AND slug IS NOT NULL;
CREATE UNIQUE INDEX IF NOT EXISTS idx_official_results_fixture_key_unique ON public.official_results(fixture_key) WHERE fixture_key IS NOT NULL;

INSERT INTO public.competitions (slug, name, type, region, description, is_active, featured_order, sort_order)
SELECT slug, name, type, region, description, is_active, featured_order, sort_order
FROM jsonb_to_recordset('[{"slug": "ucl", "name": "UEFA Champions League", "type": "cup", "region": "Europe", "is_active": true, "featured_order": 1, "sort_order": 1, "description": "Europe''s premier club football competition"}, {"slug": "facup", "name": "FA Cup", "type": "cup", "region": "England", "is_active": true, "featured_order": 2, "sort_order": 2, "description": "The world''s oldest football knockout competition"}, {"slug": "carabao", "name": "Carabao Cup", "type": "cup", "region": "England", "is_active": true, "featured_order": 3, "sort_order": 3, "description": "English Football League Cup"}, {"slug": "worldcup", "name": "FIFA World Cup", "type": "international", "region": "Global", "is_active": true, "featured_order": 4, "sort_order": 4, "description": "The pinnacle of international football"}, {"slug": "euros", "name": "UEFA European Championship", "type": "international", "region": "Europe", "is_active": true, "featured_order": 5, "sort_order": 5, "description": "Europe''s international championship"}, {"slug": "premier-league", "name": "Premier League", "type": "league", "region": "England", "is_active": true, "featured_order": 6, "sort_order": 6, "description": "England''s top-flight football league"}, {"slug": "laliga", "name": "La Liga", "type": "league", "region": "Spain", "is_active": true, "featured_order": 7, "sort_order": 7, "description": "Spain''s top-flight football league"}]'::jsonb) AS x(
  slug text, name text, type text, region text, description text, is_active boolean, featured_order integer, sort_order integer
)
ON CONFLICT (slug) DO UPDATE SET
  name = EXCLUDED.name,
  type = EXCLUDED.type,
  region = EXCLUDED.region,
  description = EXCLUDED.description,
  is_active = EXCLUDED.is_active,
  featured_order = EXCLUDED.featured_order,
  sort_order = EXCLUDED.sort_order,
  updated_at = now();

